def test_merge_asof_indicator():
    # Test that indicator=True adds a _merge column
    left = pd.DataFrame(
        {
            "a": [1, 5, 10],
            "left_val": ["a", "b", "c"],
        }
    )
    right = pd.DataFrame(
        {
            "a": [1, 2, 3, 6, 7],
            "right_val": [1, 2, 3, 6, 7],
        }
    )
    result = merge_asof(left, right, on="a", indicator=True)

    # All rows are matched (left join behavior), so all should be "both"
    expected = left.copy()
    expected["right_val"] = [1.0, 3.0, 7.0]
    expected["_merge"] = pd.Categorical(
        ["both", "both", "both"], categories=["left_only", "right_only", "both"]
    )
    tm.assert_frame_equal(result, expected)


