def test_merge_asof_indicator_with_by():
    # Test indicator works with 'by' parameter
    quotes = pd.DataFrame(
        {
            "time": pd.to_datetime(
                [
                    "2016-05-25 13:30:00.023",
                    "2016-05-25 13:30:00.048",
                    "2016-05-25 13:30:00.075",
                ]
            ),
            "ticker": ["MSFT", "GOOG", "AAPL"],
            "bid": [51.95, 720.50, 98.55],
        }
    )
    trades = pd.DataFrame(
        {
            "time": pd.to_datetime(
                [
                    "2016-05-25 13:30:00.023",
                    "2016-05-25 13:30:00.048",
                ]
            ),
            "ticker": ["MSFT", "GOOG"],
            "price": [51.95, 720.77],
        }
    )
    result = merge_asof(trades, quotes, on="time", by="ticker", indicator=True)

    # All trades should have matching quotes
    expected = pd.DataFrame(
        {
            "time": pd.to_datetime(
                [
                    "2016-05-25 13:30:00.023",
                    "2016-05-25 13:30:00.048",
                ]
            ),
            "ticker": ["MSFT", "GOOG"],
            "price": [51.95, 720.77],
            "bid": [51.95, 720.50],
            "_merge": pd.Categorical(
                ["both", "both"], categories=["left_only", "right_only", "both"]
            ),
        }
    )
    tm.assert_frame_equal(result, expected)

